record_types.code:
type gsl_wavelet is record
   c_type : access constant gsl_wavelet_type;
   h1 : access double;
   g1 : access double;
   h2 : access double;
   g2 : access double;
   nc : aliased size_t;
   offset : aliased size_t;
end record;

type gsl_wavelet_type is record
   name : Interfaces.C.Strings.chars_ptr;
   init : access function
        (arg1 : System.Address;
         arg2 : System.Address;
         arg3 : System.Address;
         arg4 : System.Address;
         arg5 : access size_t;
         arg6 : access size_t;
         arg7 : size_t) return int;
end record;

type gsl_wavelet_workspace is record
   scratch : access double;
   n : aliased size_t;
end record;

