function transform
  (w : access constant gsl_wavelet;
   data : access double;
   stride : size_t;
   n : size_t;
   dir : gsl_wavelet_direction;
   work : access gsl_wavelet_workspace) return int

function transform_forward
  (w : access constant gsl_wavelet;
